sections.body:
{
  "structuralMechanical": [
    {
      "condition": "Osteoarthritis (OA)",
      "features": "Insidious onset, age >45, morning stiffness <30 minutes, worse with activity, crepitus, bony enlargement, no systemic symptoms. Most common cause in older adults.",
      "diagnostics": "Clinical diagnosis; X-ray (joint space narrowing, osteophytes, subchondral sclerosis) confirms if >45 with typical features.",
      "management": "First-line: exercise therapy + weight loss; acetaminophen PRN; topical NSAIDs (diclofenac gel); oral NSAIDs if renal function adequate; intra-articular corticosteroid injections for moderate-severe flares."
    },
    {
      "condition": "Patellofemoral Pain Syndrome (PFPS)",
      "features": "Anterior knee pain, worse with stairs, squatting, prolonged sitting ('movie sign'). Common in young active adults and adolescents. No effusion.",
      "diagnostics": "Clinical; Clarke's test (patellar grind). X-ray to rule out osteochondral lesion if acute or atypical.",
      "management": "PT with quadriceps strengthening (VMO focus), activity modification, taping, NSAIDs short-term."
    },
    {
      "condition": "Meniscal Injury",
      "features": "Medial or lateral joint line tenderness, McMurray's test positive, joint effusion common, locking or clicking. Acute (twisting mechanism) or degenerative (older adult, no trauma).",
      "diagnostics": "Clinical assessment + MRI for acute tears; X-ray to rule out fracture if acute traumatic.",
      "management": "Degenerative: conservative (PT, analgesics); acute bucket-handle or locking: orthopedic referral."
    },
    {
      "condition": "Prepatellar / Pes Anserine Bursitis",
      "features": "Prepatellar: localized anterior swelling over patella, occupation-related (kneeling). Pes anserine: medial pain 2–3 cm below medial joint line, common in obese older adults with OA.",
      "diagnostics": "Clinical. Aspirate prepatellar bursa only if septic bursitis suspected (warmth, fever, history of skin breach).",
      "management": "RICE, NSAIDs, padding, avoid kneeling; corticosteroid injection if refractory."
    },
    {
      "condition": "Ligamentous Sprain (MCL/LCL/ACL/PCL)",
      "features": "Traumatic mechanism (valgus stress for MCL, varus for LCL, pivot/deceleration for ACL). Acute swelling, instability, positive stress tests.",
      "diagnostics": "Clinical stress tests + X-ray (Ottawa Knee Rules to exclude fracture); MRI for surgical planning.",
      "management": "MCL/LCL grade I-II: conservative. ACL/PCL complete tear: orthopedic referral."
    }
  ],
  "inflammatory": [
    {
      "condition": "Gout",
      "features": "Acute monoarthritis, severe pain peaking within 24 hours, swollen erythematous warm joint, often 1st MTP but can affect knee. Associated with hyperuricemia, alcohol, diuretic use.",
      "diagnostics": "Joint aspiration (gold standard): negatively birefringent urate crystals. Serum uric acid may be normal during acute attack. X-ray shows punched-out erosions with overhanging edge in chronic gout.",
      "management": "Acute: colchicine (0.6 mg BID x 3 days or until resolved), or NSAIDs, or systemic corticosteroids if contraindicated. Long-term: urate-lowering therapy (allopurinol) if ≥2 flares/year or tophi."
    },
    {
      "condition": "Septic Arthritis",
      "features": "EMERGENCY. Acute monoarthritis with fever, severe pain, limited ROM, hot joint. Risk factors: immunocompromised, IV drug use, recent joint injection, prior joint disease, skin infection.",
      "diagnostics": "Joint aspiration STAT: WBC >50,000/mm³ (often >100,000), PMN predominance, Gram stain + culture. Blood cultures. CBC, ESR, CRP elevated.",
      "management": "Immediate ED referral + joint washout. Do NOT give antibiotics before aspiration if possible — confirm diagnosis first."
    },
    {
      "condition": "Rheumatoid Arthritis",
      "features": "Symmetric polyarthritis, morning stiffness >1 hour, affects MCPs/PIPs/wrists preferentially; knee involvement in established disease. Systemic: fatigue, low-grade fever, RF/anti-CCP positive.",
      "diagnostics": "RF, anti-CCP, ESR, CRP, joint X-rays (juxta-articular osteopenia, erosions); rheumatology referral.",
      "management": "DMARDs (methotrexate first-line); bridge with NSAIDs/prednisone."
    },
    {
      "condition": "Pseudogout (CPPD)",
      "features": "Calcium pyrophosphate deposition; elderly, involves knee (wrist, MCP also). Presents similarly to gout. X-ray shows chondrocalcinosis (linear calcification in cartilage).",
      "diagnostics": "Aspiration: positively birefringent rhomboid crystals.",
      "management": "Same as gout acutely (colchicine, NSAIDs, steroids); no equivalent urate-lowering therapy."
    }
  ],
  "referred": [
    {
      "condition": "Hip OA / Hip Pathology",
      "features": "Anterior knee or medial thigh pain referred from hip; reduced internal rotation of hip on exam. Key: knee exam is normal. ALWAYS examine the hip when knee pain is atypical.",
      "management": "Address hip pathology; hip X-ray."
    },
    {
      "condition": "Lumbar Radiculopathy (L3-L4)",
      "features": "Anterior thigh/knee pain in L3-L4 dermatomal pattern; associated with low back pain, positive femoral stretch test.",
      "management": "Spine imaging + PT."
    }
  ]
}

{
  "initialEvaluation": [
    "History: onset (acute vs insidious), mechanism (trauma vs atraumatic), location (anterior/medial/lateral/posterior), aggravating factors (stairs, squatting, rest pain), morning stiffness duration, systemic symptoms",
    "Physical exam: gait, alignment (valgus/varus), effusion assessment (ballottement, bulge sign), palpation (joint lines, patella, bursae), ROM active/passive, special tests (McMurray, Lachman, valgus/varus stress, Clarke's)",
    "ALWAYS examine the hip and lower lumbar spine in every knee complaint"
  ],
  "imagingDecision": {
    "Ottawa_Knee_Rules_indications": "Age ≥55, fibular head tenderness, isolated patellar tenderness, inability to flex to 90°, inability to bear weight for 4 steps — if any present, X-ray indicated",
    "MRI_indications": "Suspected ligamentous tear, meniscal injury in surgical candidate, atypical presentation, prior X-ray negative but significant functional impairment"
  },
  "conservativeManagement": "RICE (Rest, Ice, Compression, Elevation) for acute injuries; scheduled acetaminophen for OA; short-course NSAIDs with GI protection; PT referral; activity modification; weight loss counseling for OA/PFPS"
}

{
  "adult_general": "Multi-step decision making around imaging (Ottawa rules), medication selection (NSAIDs vs acetaminophen based on renal function, GI risk), and PT vs injection timing",
  "older_adult": "OA predominates; NSAIDs require caution (GI, cardiovascular, renal); topical NSAIDs preferred; intra-articular injections as bridge; total knee arthroplasty for refractory severe OA",
  "young_active_adult": "PFPS and ligamentous injuries predominate; avoid premature escalation to imaging before conservative trial"
}

{
  "conservativeCourse": "Reassess at 4-6 weeks for structural/mechanical diagnoses treated conservatively",
  "escalationTriggers": "No improvement after 6-8 weeks of conservative therapy → X-ray if not done; consider orthopedic referral",
  "goutyArthritis": "After acute gout resolves, check serum uric acid (goal <6 mg/dL on ULT); initiate allopurinol if indicated; reassess adherence at 4-6 weeks",
  "OA": "Quarterly assessment of pain, function, and BMI; review NSAID use and GI/renal safety annually"
}

{
  "definitions": {
    "uncomplicatedUTI": "Acute cystitis in a non-pregnant adult woman with normal urinary tract anatomy and immune status. Symptoms: dysuria, frequency, urgency, suprapubic discomfort. No fever, no flank pain, no systemic illness.",
    "complicatedUTI": "Any UTI with features suggesting upper tract involvement, systemic illness, or host/structural factors that increase treatment failure risk",
    "complicatingFactors": [
      "Male sex",
      "Pregnancy",
      "Diabetes mellitus (especially poorly controlled)",
      "Indwelling urinary catheter",
      "Urinary tract anatomic abnormality or obstruction",
      "Immunocompromised state",
      "Symptoms present >7 days before presentation",
      "Prior treatment failure or recurrence within 2 weeks",
      "Recent urinary tract instrumentation"
    ]
  },
  "pyelonephritis": {
    "features": "Flank pain (costovertebral angle tenderness), fever ≥38°C, nausea/vomiting, rigors. May also have lower urinary symptoms. CBC: leukocytosis. Urinalysis: pyuria + bacteriuria, WBC casts pathognomonic.",
    "admissionCriteria": "Inability to tolerate oral fluids, severe illness, immunocompromise, pregnancy, compliance concerns, failure of outpatient therapy"
  },
  "asymptomatic_bacteriuria": {
    "definition": "Significant bacteriuria (≥10^5 CFU/mL) without UTI symptoms",
    "treatWhen": "Pregnancy (screen and treat) and pre-urological procedure only",
    "doNotTreat": "Elderly, diabetics, catheterized patients, otherwise healthy adults — treatment increases resistance without benefit"
  }
}

{
  "older_adult": "Bacteriuria very common in elderly (>50% in women, >30% in men in long-term care) — DO NOT TREAT without symptoms. Atypical presentations: confusion, falls, decline in function may be the only symptoms of UTI in frail elderly. However, bacteriuria + atypical symptoms is not always causal — clinical judgment required.",
  "reproductive_health": "Pregnancy screening mandatory. Use pregnancy-safe antibiotics. Postmenopausal women benefit from vaginal estrogen for recurrence prevention.",
  "diabetes": "Higher risk for complications; obtain culture; consider 7-10 day course; monitor for emphysematous pyelonephritis (CT if not improving)"
}

{
  "uncomplicated": "No test-of-cure culture needed if symptoms resolve completely; reassess if symptoms persist at 48-72 hours",
  "pyelonephritis": "Test-of-cure culture 1 week post-treatment; follow-up visit at 48-72 hours if outpatient",
  "pregnancy": "Test-of-cure culture essential after treatment; repeat screening at 28-32 weeks",
  "recurrentUTI": "Culture-direct all episodes; reassess prevention strategy at 6-12 months"
}

{
  "older_adult": {
    "targets": "Liberalize A1c target to 7.5-8.0%; primary goal is avoiding hypoglycemia and functional decline",
    "preferred_agents": "GLP-1 RA (no hypoglycemia risk), DPP-4 inhibitors (safe, weight neutral), linagliptin (no renal adjustment)",
    "avoid": "Glyburide (Beers Criteria); long-acting sulfonylureas; complex insulin regimens without adequate support; NSAIDs concurrently",
    "renal_dosing": "Metformin: hold if eGFR <30; reduce if eGFR 30-45. Sitagliptin: dose-reduce based on eGFR. SGLT-2: check indication-specific eGFR thresholds.",
    "polypharmacy": "Review entire medication list at every visit; deprescribing opportunities often arise as T2DM improves with GLP-1/SGLT-2"
  },
  "chronic_disease": "Longitudinal monitoring: A1c q3-6 months; annual microalbuminuria, eGFR, lipids, foot exam, dilated eye exam, blood pressure; dental and depression screening"
}

{
  "diagnosis": {
    "spirometry": "Post-bronchodilator FEV1/FVC <0.70 confirms airflow obstruction. Required for diagnosis — do NOT diagnose COPD by symptoms alone.",
    "GOLD_spirometric_grades": {
      "GOLD_1": "FEV1 ≥80% predicted — mild",
      "GOLD_2": "FEV1 50-79% — moderate",
      "GOLD_3": "FEV1 30-49% — severe",
      "GOLD_4": "FEV1 <30% — very severe"
    }
  },
  "GOLD_ABE_assessment": {
    "description": "GOLD 2024 ABE replaces ABCD. Uses symptom burden + exacerbation history (NOT spirometry grade) for inhaler escalation decisions.",
    "symptomTools": "CAT (COPD Assessment Test): ≥10 = more symptoms; mMRC dyspnea scale ≥2 = more symptoms",
    "groupA": "0-1 moderate exacerbations/year, not leading to hospitalization, AND fewer symptoms (CAT <10 or mMRC 0-1)",
    "groupB": "0-1 moderate exacerbations, not hospitalizing, AND more symptoms (CAT ≥10 or mMRC ≥2)",
    "groupE": "≥2 moderate exacerbations OR ≥1 leading to hospitalization (regardless of symptom burden)"
  },
  "inhalerClasses": {
    "SABA": "Short-acting beta-2 agonist (albuterol MDI) — rescue only; no scheduled use as sole therapy",
    "SAMA": "Short-acting muscarinic antagonist (ipratropium) — rescue alternative; less bronchospasm rebound than SABA",
    "LAMA": "Long-acting muscarinic antagonist (tiotropium HandiHaler or Respimat; umeclidinium; aclidinium) — cornerstone maintenance; once daily",
    "LABA": "Long-acting beta-2 agonist (salmeterol, formoterol, indacaterol) — BID or QD; do NOT use without LAMA in COPD (unlike asthma)",
    "ICS": "Inhaled corticosteroid (fluticasone, budesonide) — NOT first-line in COPD; adds benefit in eosinophilic phenotype (blood eosinophils ≥300) or frequent exacerbators"
  },
  "initialInhalerSelection_GOLD2024": {
    "groupA": "Offer bronchodilator (any class) — SABA PRN or LAMA if more persistent symptoms",
    "groupB": "LAMA alone or LAMA + LABA (if highly symptomatic)",
    "groupE": "LAMA + LABA as initial therapy; add ICS if blood eosinophils ≥300 cells/μL or frequent exacerbations despite LAMA+LABA"
  },
  "ICS_appropriateUse": {
    "add_when": "Blood eosinophils ≥300 cells/μL, ≥2 exacerbations/year despite LAMA+LABA, concurrent asthma-COPD overlap",
    "avoid_when": "Recurrent pneumonia (ICS increases risk), blood eosinophils <100 cells/μL, mycobacterial infection",
    "triple_therapy": "LAMA + LABA + ICS (e.g., fluticasone/umeclidinium/vilanterol — Trelegy Ellipta) — highest benefit in eosinophilic/exacerbation-prone; proven to reduce all-cause mortality (IMPACT trial)"
  }
}

{
  "older_adult": {
    "inhalerChallenges": "Arthritis may prevent proper MDI actuation — switch to soft-mist inhaler (Respimat) or DPI with spacer; assess technique at every visit",
    "cognitive_decline": "Simplified once-daily regimens preferred (tiotropium HandiHaler or umeclidinium); caregiver involvement",
    "polypharmacy": "Beta-blockers generally safe in COPD (cardioselective) but may worsen bronchoconstriction in very severe disease; avoid high-dose anticholinergics (risk of urinary retention, cognitive effects)",
    "oxygen_titration": "Target SpO2 88-92%; do not over-oxygenate"
  },
  "chronic_disease": "Longitudinal spirometry annually; CAT or mMRC at each visit; exacerbation log review; comorbidity burden (cardiovascular disease, depression, osteoporosis, muscle wasting)"
}

{
  "schedule": "Stable COPD: every 3-6 months; after exacerbation: 4-6 week follow-up (reassess recovery, adjust therapy, check spirometry at 8+ weeks post-exacerbation)",
  "monitoring": "SpO2 at each visit; spirometry annually or with significant change; sputum characteristics; exacerbation log; weight (muscle wasting/cachexia is poor prognostic sign); depression/anxiety screening (PHQ-9, GAD-7)",
  "bloodEosinophils": "Check annually to guide ICS use decisions",
  "referrals": "Pulmonology for GOLD 3-4, diagnostic uncertainty, frequent exacerbators, lung transplant evaluation; palliative care for advanced COPD with declining trajectory"
}

{
  "assessment_flow": [
    "Step 1: Screen for SNOOP4 red flags — if ANY present → imaging and/or ED",
    "Step 2: If no red flags → characterize the headache (onset, location, quality, duration, associated symptoms, triggers)",
    "Step 3: Match to primary headache diagnosis",
    "Step 4: Treat acute attack; assess need for prophylaxis",
    "Step 5: Neuroimaging in primary care: NOT routinely indicated for classic migraine/tension; indicated for: atypical features, progressive pattern, new headache in >50, focal neuro signs, immunocompromise, malignancy history"
  ]
}

{
  "urgent_care": "All red flag headaches should be dispositioned to ED from urgent care, not managed and discharged. Document that red flags were screened.",
  "adult": "In reproductive-age women: consider hormonal triggers for migraine; avoid topiramate and valproate if pregnancy possible (teratogenic). Estrogen-containing OCP may worsen migraine with aura (increased stroke risk).",
  "older_adult": "New headache >50 requires imaging to exclude mass, subdural, or vasculitis; GCA must be ruled out"
}

{
  "primary_headache": "1-2 month follow-up after initiating prophylaxis; headache diary review; functional status assessment (MIDAS)",
  "prophylaxis_trial": "Minimum 8-12 week trial at therapeutic dose before declaring failure",
  "neurology_referral": "Failure of ≥2 prophylactic agents; status migrainosus (>72h continuous migraine); diagnostic uncertainty; suspected secondary headache"
}

{
  "definitions": {
    "syncope": "Transient loss of consciousness (TLOC) due to global cerebral hypoperfusion, with spontaneous recovery. Distinguishes from seizure, hypoglycemia, and psychogenic unresponsiveness.",
    "presyncope": "Near-fainting — lightheadedness, visual dimming, weakness without TLOC. Managed and risk-stratified similarly."
  },
  "categories": {
    "vasovagal": {
      "features": "Prodrome (nausea, diaphoresis, blurred vision, lightheadedness lasting seconds to minutes), triggered by emotion/pain/prolonged standing/hot environment, brief LOC <5 min, rapid full recovery, no postictal confusion",
      "riskFactors": "Young, healthy; typical story is compelling; most benign etiology",
      "subtypes": "Classic vasovagal; carotid sinus hypersensitivity (elderly, syncope with head turning/collar pressure); situational (cough, micturition, defecation)"
    },
    "orthostatic_hypotension": {
      "features": "Syncope or presyncope within 3 minutes of standing, BP drop ≥20/10 mmHg systolic/diastolic",
      "causes": "Dehydration, medications (antihypertensives, alpha-blockers, diuretics, tricyclics), autonomic neuropathy (DM, Parkinson's), adrenal insufficiency",
      "evaluation": "Orthostatic vital signs (supine → standing at 1, 2, 3 min)"
    },
    "cardiac_arrhythmic": {
      "features": "No prodrome or extremely brief prodrome, occurs seated or supine, exercise-related syncope, palpitations before LOC, prolonged LOC, rapid recovery",
      "highRiskArrhythmias": [
        "Ventricular tachycardia",
        "Ventricular fibrillation",
        "Complete heart block / high-degree AV block",
        "Sick sinus syndrome",
        "Wolff-Parkinson-White (WPW) with pre-excitation → AF → rapid VF"
      ],
      "ECG_red_flags": [
        "QTc prolongation >470 ms (females) or >450 ms (males) — risk of torsades de pointes",
        "Brugada pattern — coved ST elevation V1-V2 with RBBB morphology",
        "Delta wave (short PR + slurred QRS upstroke) — WPW",
        "Complete LBBB in a patient with syncope — consider structural disease",
        "Epsilon wave in V1-V3 — ARVC (arrhythmogenic right ventricular cardiomyopathy)",
        "Sinus bradycardia <40 bpm; long pauses >3 seconds",
        "ST elevation or significant ST depression — ACS"
      ]
    },
    "cardiac_structural": {
      "features": "Exertional syncope is HIGH RISK until proven otherwise (rule out HOCM, severe AS, pulmonary hypertension, coronary artery disease)",
      "conditions": [
        "Hypertrophic obstructive cardiomyopathy (HOCM)",
        "Severe aortic stenosis",
        "Pulmonary arterial hypertension",
        "Arrhythmogenic cardiomyopathy"
      ],
      "evaluation": "Echocardiogram mandatory if structural suspected"
    },
    "neurological": {
      "seizure_vs_syncope": {
        "favorSeizure": "Prolonged LOC >5 min, postictal confusion, tongue biting (lateral), incontinence during event, tonic-clonic movements persisting >30 seconds, no prodrome",
        "favorSyncope": "Brief LOC <60 sec, rapid full recovery, clear prodrome, provoked by situational trigger",
        "note": "Brief myoclonic jerks can occur in syncope (anoxic seizure) — do not over-diagnose epilepsy"
      },
      "TIA_vs_syncope": "TIA does NOT typically cause TLOC (vertebrobasilar TIA rarely does; carotid TIA essentially never). New-onset syncope labeled as TIA without focal deficit is usually incorrect."
    }
  },
  "riskStratification": {
    "ROSE_rule_highRisk": [
      "Bradycardia <50 on ECG or monitoring",
      "Troponin elevation",
      "Signs of heart failure",
      "Hematocrit <30%",
      "Oxygen saturation <94%",
      "BNP >300 pg/mL"
    ],
    "SanFrancisco_rule": "Congestive heart failure history, hematocrit <30%, EKG abnormality, shortness of breath, SBP <90 — if any present → hospital admission",
    "lowRisk_outpatient": "Age <40, no structural heart disease, classic vasovagal story, normal ECG, asymptomatic vital signs, no family history of sudden cardiac death"
  }
}

{
  "urgent_care": "Disposition decision is key. Use validated risk tool (ROSE, SF Syncope Rule). Cannot safely send home: exertional syncope, abnormal ECG, structural heart disease, no prodrome, troponin elevation.",
  "older_adult": "Higher baseline cardiac risk; more likely orthostatic (polypharmacy, autonomic dysfunction); falls injury secondary to syncope may be primary morbidity concern; review medication list for offending agents (antihypertensives, diuretics, alpha-blockers, PDE-5 inhibitors)"
}

{
  "vasovagal_outpatient": "Close follow-up in 1-2 weeks; episode log; driving restrictions discussion (state law varies — typically restrict driving until event-free for specified period)",
  "cardiac_unexplained": "Holter/event monitor; cardiology referral within 1-2 weeks; restrict strenuous activity until clearance",
  "driving_counseling": "All syncope patients require explicit discussion about driving — document. Most states require reporting to DMV for recurrent or high-risk syncope."
}

{
  "definitions": {
    "hypertensiveUrgency": "BP ≥180/120 mmHg WITHOUT acute end-organ damage. Patient may have headache, anxiety, or be asymptomatic. Managed by restarting/adjusting medications and close outpatient follow-up — NOT acute IV agents.",
    "hypertensiveEmergency": "BP ≥180/120 mmHg WITH acute end-organ damage. Requires immediate ED transfer for IV antihypertensive therapy.",
    "endOrganDamage_markers": [
      "Brain: hypertensive encephalopathy (confusion, severe headache, cortical blindness, seizure), stroke, intracranial hemorrhage",
      "Eye: papilledema, flame hemorrhages, exudates on fundoscopy (hypertensive retinopathy grade III-IV)",
      "Heart: acute decompensated heart failure (dyspnea, pulmonary edema), ACS (chest pain + ECG changes), aortic dissection",
      "Kidney: acute kidney injury (creatinine doubling or rapid rise), microangiopathic hemolytic anemia (MAHA) in malignant HTN",
      "Eclampsia: seizures + HTN in pregnancy"
    ]
  },
  "specialEmergencies": {
    "aorticDissection": {
      "keyFeatures": "Tearing/ripping chest or back pain, radiating to interscapular area; BP differential between arms (>20 mmHg); pulse deficits; history of Marfan's, bicuspid aortic valve, uncontrolled HTN",
      "management": "ED IMMEDIATELY; target SBP <120 mmHg with IV labetalol + esmolol; avoid pure vasodilators without HR control (reflex tachycardia worsens shear force)"
    },
    "hypertensiveEncephalopathy": {
      "keyFeatures": "Severe headache, confusion, visual disturbances, seizure; BP markedly elevated; PRES (posterior reversible encephalopathy syndrome) on MRI",
      "management": "ED; IV agents (nicardipine, labetalol); reduce MAP by 10-15% in first hour, then 15% over next 23 hours — NOT a rapid drop"
    },
    "eclampsia": {
      "keyFeatures": "Pregnant or postpartum (up to 6 weeks), BP ≥160/110, seizure, headache, visual changes, RUQ pain (HELLP syndrome)",
      "management": "911/ED; magnesium sulfate for seizure prophylaxis; labetalol or hydralazine for BP; immediate delivery consideration"
    }
  },
  "resistantHypertension": {
    "definition": "BP above goal despite ≥3 antihypertensives at maximum tolerated doses including a diuretic",
    "secondaryCauses": [
      "Primary hyperaldosteronism (check aldosterone/renin ratio)",
      "CKD (check eGFR, urine albumin)",
      "Obstructive sleep apnea (STOP-BANG questionnaire)",
      "Renal artery stenosis (bruit, flash pulmonary edema, renal function worsening on ACEi/ARB)",
      "Thyroid disease (TSH)",
      "Pheochromocytoma (rare — headache, palpitations, diaphoresis triad)"
    ],
    "management": "Optimize existing regimen; consider adding spironolactone 25-50 mg for primary aldosteronism; refer to nephrology or hypertension specialist"
  }
}

{
  "older_adult": [
    "Isolated systolic HTN most common — SBP ≥140 with DBP <90; treat SBP to <130-140",
    "Orthostatic hypotension more common — check standing BP before intensifying therapy",
    "Medication interactions: NSAIDs raise BP significantly in older adults on antihypertensives",
    "Volume depletion from diuretics can precipitate acute kidney injury; check BMP periodically",
    "Caution with dihydropyridine calcium channel blockers (amlodipine) — can cause dependent edema; not a sign of heart failure"
  ],
  "urgent_care": "BP reading in urgent care: always confirm with repeat measurement after rest; check both arms; rule out measurement error before escalating"
}

{
  "urgency": "24-48 hour follow-up; repeat BP; medication reconciliation; lifestyle reinforcement",
  "newlyDiagnosed_severeHTN": "Basic metabolic panel, lipid panel, urinalysis, urine albumin, EKG at baseline; reassess in 1 month",
  "resistantHTN": "Secondary workup; nephrology or hypertension specialist; minimize salt intake (<2g/day); optimize diuretic; CPAP if OSA"
}

{
  "constitutionalRedFlags": {
    "unexplainedWeightLoss": "Loss of >5% body weight over 6-12 months without clear cause (depression, new diet, intentional) — warrants systematic cancer workup: CBC, CMP, LFTs, LDH, UA, TSH, CXR. If >50, add PSA (males) and consider colonoscopy.",
    "nightSweats": "Drenching night sweats requiring change of clothes/bedding + weight loss + lymphadenopathy = classic lymphoma presentation → CBC with differential, LDH, uric acid, CT scan",
    "fatigue_unexplained": "Profound, new fatigue not explained by thyroid, anemia, depression, sleep apnea — CBC (rule out leukemia), calcium (hypercalcemia of malignancy), ESR/CRP"
  },
  "systemSpecificRedFlags": {
    "GI_ALARM": [
      "Dysphagia (progressive) — upper GI malignancy; alarm symptom requiring upper endoscopy",
      "Hematemesis or melena — upper GI bleeding; urgent endoscopy",
      "New rectal bleeding in >40 without clear anorectal source — colorectal cancer workup",
      "Iron deficiency anemia in postmenopausal woman or any man — upper + lower GI endoscopy (bi-directional) until source found",
      "Unexplained abdominal pain + weight loss in older adult — pancreatic or GI malignancy",
      "Change in bowel habits >6 weeks in adult >50 — colonoscopy",
      "Unexplained palpable abdominal mass — CT abdomen/pelvis"
    ],
    "respiratory": [
      "Hemoptysis (any) in adult >40 + smoker — chest CT; bronchoscopy if CT negative but clinical suspicion",
      "Persistent cough >8 weeks not explained by URTI, ACEi, GERD, or asthma — CXR; if smoker >50, low-dose CT lung cancer screening (LDCT)",
      "Unexplained hoarseness >3 weeks — laryngoscopy referral"
    ],
    "breast": [
      "New palpable breast lump — diagnostic mammogram + ultrasound; do NOT dismiss in any age group",
      "Nipple discharge (spontaneous, unilateral, bloody) — mammogram + ductography referral",
      "Skin changes (peau d'orange, nipple retraction, inflammatory changes) — urgent referral"
    ],
    "urological": [
      "Visible hematuria (gross) in adult — CT urogram + cystoscopy referral regardless of absence of pain",
      "Microscopic hematuria in adult >35 — urology referral for cystoscopy",
      "New palpable testicular mass — urgent ultrasound (tumor marker: AFP, hCG, LDH)"
    ],
    "neurological": [
      "New seizure in adult >40 with no prior seizure disorder — brain MRI with contrast",
      "Progressive headache with vomiting, worse in the morning — mass effect → CT/MRI"
    ],
    "skin": [
      "ABCDEs: Asymmetry, Border irregularity, Color variegation, Diameter >6mm, Evolution — any E (change) = urgent dermatology referral or biopsy",
      "New non-healing ulcer or nodule with induration in sun-exposed area — squamous cell carcinoma"
    ],
    "lymphadenopathy": [
      "Painless, firm, progressively enlarging lymph node >1 cm persistent >4 weeks without infectious cause",
      "Supraclavicular lymphadenopathy is ALWAYS concerning (Virchow's node) — urgent workup"
    ]
  },
